const fs = require('fs');
const dataPath = '/home/node/aerys-evals/baseline.json';
let dataset;
try {
  dataset = JSON.parse(fs.readFileSync(dataPath, 'utf8'));
} catch(e) {
  return [{json: {error: 'Could not read baseline.json at ' + dataPath + '. Ensure evals volume is mounted in docker-compose.yml and container is restarted.', detail: e.message}}];
}
const staticData = $getWorkflowStaticData('global');
staticData.scores = [];
staticData.details = [];
staticData.total = dataset.length;

return dataset.map(tc => ({json: tc}));

const coreOutput = $json;
const testInput = $('Build Test Input').item.json;

const agentResponse = coreOutput.output || coreOutput.text || coreOutput.content || JSON.stringify(coreOutput);

return [{json: {
  test_case_id: testInput._test_case_id,
  category: testInput._test_category,
  user_message: testInput.message_text,
  expected_behavior: testInput._expected_behavior,
  agent_response: agentResponse,
  start_ts: testInput._start_ts,
  response_time_ms: Date.now() - testInput._start_ts
}}];

const data = $json;

const systemPrompt = 'You are an expert evaluator for an AI assistant named Aerys. Given a user message, the expected behavior criteria, and Aerys\'s actual response, score the response 1-5:\n\n5 = Perfect: accurate, natural, in Aerys\'s voice, directly addresses the question, meets all expected behavior criteria\n4 = Good: mostly correct, minor issues with tone or completeness\n3 = Acceptable: correct but mechanical, missing personality, or slightly off-topic\n2 = Poor: partially wrong, ignores the question, or very out of character\n1 = Fail: wrong, harmful, complete non-answer, or error message\n\nRespond with JSON only:\n{"reasoning": "<1-2 sentence analysis>", "score": <1-5>}';

const userPrompt = 'User message: ' + data.user_message + '\n\nExpected behavior: ' + data.expected_behavior + '\n\nAerys response: ' + data.agent_response;

return [{json: {
  test_case_id: data.test_case_id,
  category: data.category,
  user_message: data.user_message,
  expected_behavior: data.expected_behavior,
  agent_response: data.agent_response,
  start_ts: data.start_ts,
  response_time_ms: data.response_time_ms,
  _judge_body: {
    model: 'anthropic/claude-sonnet-4-5',
    max_tokens: 500,
    temperature: 0,
    messages: [
      {role: 'system', content: systemPrompt},
      {role: 'user', content: userPrompt}
    ]
  }
}}];

const judgeRaw = $json;
const testData = $('Build Judge Request').item.json;

let score = 3;
let reasoning = 'Parse error - defaulting to 3';

try {
  if (judgeRaw.error) {
    reasoning = 'LLM Judge HTTP error: ' + JSON.stringify(judgeRaw.error);
    score = 0;
  } else {
    const content = judgeRaw.choices[0].message.content;
    const cleaned = content.replace(/```json\n?/g, '').replace(/```/g, '').trim();
    const parsed = JSON.parse(cleaned);
    score = parsed.score || 3;
    reasoning = parsed.reasoning || parsed.reasoning_summary || 'No reasoning provided';
  }
} catch(e) {
  reasoning = 'Parse failed: ' + e.message + ' | Raw: ' + JSON.stringify(judgeRaw).substring(0, 200);
}

const staticData = $getWorkflowStaticData('global');
if (!staticData.scores) staticData.scores = [];
if (!staticData.details) staticData.details = [];

staticData.scores.push(score);
staticData.details.push({
  id: testData.test_case_id,
  category: testData.category,
  score: score,
  reasoning: reasoning,
  response_time_ms: testData.response_time_ms,
  agent_response_preview: (testData.agent_response || '').substring(0, 200)
});

return [{json: {
  test_case_id: testData.test_case_id,
  category: testData.category,
  score: score,
  reasoning: reasoning,
  response_time_ms: testData.response_time_ms,
  progress: staticData.scores.length + '/' + (staticData.total || '?')
}}];

const staticData = $getWorkflowStaticData('global');
const scores = staticData.scores || [];
const details = staticData.details || [];

if (scores.length === 0) {
  return [{json: {error: 'No scores collected', details: []}}];
}

const avg = scores.reduce((a, b) => a + b, 0) / scores.length;

const byCategory = {};
details.forEach(d => {
  if (!byCategory[d.category]) {
    byCategory[d.category] = {scores: [], count: 0, total_response_time_ms: 0};
  }
  byCategory[d.category].scores.push(d.score);
  byCategory[d.category].count++;
  byCategory[d.category].total_response_time_ms += (d.response_time_ms || 0);
});

const categoryReport = {};
for (const [cat, data] of Object.entries(byCategory)) {
  const catAvg = data.scores.reduce((a, b) => a + b, 0) / data.scores.length;
  categoryReport[cat] = {
    average_score: Number(catAvg.toFixed(2)),
    count: data.count,
    min: Math.min(...data.scores),
    max: Math.max(...data.scores),
    avg_response_time_ms: Math.round(data.total_response_time_ms / data.count)
  };
}

const report = {
  baseline_run: new Date().toISOString(),
  total_cases: scores.length,
  average_score: Number(avg.toFixed(2)),
  min_score: Math.min(...scores),
  max_score: Math.max(...scores),
  by_category: categoryReport,
  details: details
};

staticData.scores = [];
staticData.details = [];
staticData.total = 0;

return [{json: report}];
